{$H+}
{$B-}
program lipdecide;

uses SysUtils, Math;

const
  PI = 3.1415926535;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 1..15;
  NPOINTS     = 2..100;
  NPTYPE      = 3..100;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : NPOINTS;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : NPOINTS;
    QUADS    : NUMQUADS;
    DIST     : real;
    N_PTS    : NPTYPE;
    K_PTS    : POINTRANGE;
    A_PTS    : POINTRANGE;
    B_PTS    : POINTRANGE;
    C_PTS    : POINTRANGE;
    D_PTS    : POINTRANGE;
    E_PTS    : POINTRANGE;
    F_PTS    : POINTRANGE;
    G_PTS    : POINTRANGE;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Dist(x1, y1, x2, y2: real): real;
begin
  Dist := Sqrt(Sqr(x1 - x2) + Sqr(y1 - y2));
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := Abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
end;

function MinRadius3(x1,y1,x2,y2,x3,y3: real): real;
var
  a, b, c, area, max_side: real;
  dot1, dot2, dot3: real;
begin
  a := Dist(x2,y2, x3,y3);
  b := Dist(x1,y1, x3,y3);
  c := Dist(x1,y1, x2,y2);

  max_side := a;
  if b > max_side then max_side := b;
  if c > max_side then max_side := c;

  dot1 := (x2-x1)*(x3-x1) + (y2-y1)*(y3-y1);
  dot2 := (x1-x2)*(x3-x2) + (y1-y2)*(y3-y2);
  dot3 := (x1-x3)*(x2-x3) + (y1-y3)*(y2-y3);

  if (dot1 <= 0.0) or (dot2 <= 0.0) or (dot3 <= 0.0) then
    MinRadius3 := max_side / 2.0
  else
  begin
    area := TriangleArea(x1, y1, x2, y2, x3, y3);
    if area = 0.0 then
      MinRadius3 := max_side / 2.0
    else
      MinRadius3 := (a * b * c) / (4.0 * area);
  end;
end;

function CalcAngle(x1,y1, x2,y2, x3,y3: real): real;
var
  a1, a2, ang: real;
begin
  a1 := ArcTan2(y1 - y2, x1 - x2);
  a2 := ArcTan2(y3 - y2, x3 - x2);
  ang := a2 - a1;
  if ang < 0.0 then ang := ang + 2.0 * PI;
  CalcAngle := ang;
end;

function GetQuad(x, y: real): integer;
begin
  if (x >= 0.0) and (y >= 0.0) then GetQuad := 1
  else if (x < 0.0) and (y >= 0.0) then GetQuad := 2
  else if (x <= 0.0) and (y < 0.0) then GetQuad := 3
  else GetQuad := 4;
end;

procedure CalcLICs;
var
  i, j, k, q: integer;
  d, a, r: real;
  cond1, cond2: boolean;
  quads_present: array[1..4] of boolean;
  quads_count: integer;
begin
  for i := 1 to 15 do CMV[i] := false;

  // LIC 1
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := Dist(X[i], Y[i], X[i+1], Y[i+1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      CMV[1] := true;
  end;

  // LIC 2
  for i := 1 to NUMPOINTS - 2 do
  begin
    r := MinRadius3(X[i],Y[i], X[i+1],Y[i+1], X[i+2],Y[i+2]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
      CMV[2] := true;
  end;

  // LIC 3
  for i := 1 to NUMPOINTS - 2 do
  begin
    if ( (REALCOMPARE(X[i], X[i+1])=EQ) and (REALCOMPARE(Y[i], Y[i+1])=EQ) ) or
       ( (REALCOMPARE(X[i+2], X[i+1])=EQ) and (REALCOMPARE(Y[i+2], Y[i+1])=EQ) ) then
      Continue;
    a := CalcAngle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if (REALCOMPARE(a, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(a, PI + PARAMETERS.EPSILON) = GT) then
      CMV[3] := true;
  end;

  // LIC 4
  for i := 1 to NUMPOINTS - 2 do
  begin
    a := TriangleArea(X[i],Y[i], X[i+1],Y[i+1], X[i+2],Y[i+2]);
    if REALCOMPARE(a, PARAMETERS.AREA1) = GT then
      CMV[4] := true;
  end;

  // LIC 5
  if NUMPOINTS >= PARAMETERS.Q_PTS then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
    begin
      for j := 1 to 4 do quads_present[j] := false;
      for j := 0 to PARAMETERS.Q_PTS - 1 do
      begin
        q := GetQuad(X[i+j], Y[i+j]);
        quads_present[q] := true;
      end;
      quads_count := 0;
      for j := 1 to 4 do
        if quads_present[j] then Inc(quads_count);
      if quads_count > PARAMETERS.QUADS then
        CMV[5] := true;
    end;
  end;

  // LIC 6
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1], X[i]) = LT then
      CMV[6] := true;
  end;

  // LIC 7
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      j := i + PARAMETERS.N_PTS - 1; // last point
      if (REALCOMPARE(X[i], X[j])=EQ) and (REALCOMPARE(Y[i], Y[j])=EQ) then
      begin
        for k := i + 1 to j - 1 do
        begin
          d := Dist(X[k], Y[k], X[i], Y[i]);
          if REALCOMPARE(d, PARAMETERS.DIST) = GT then
            CMV[7] := true;
        end;
      end
      else
      begin
        for k := i + 1 to j - 1 do
        begin
          // distance to line
          a := TriangleArea(X[k],Y[k], X[i],Y[i], X[j],Y[j]);
          d := 2.0 * a / Dist(X[i],Y[i], X[j],Y[j]);
          if REALCOMPARE(d, PARAMETERS.DIST) = GT then
            CMV[7] := true;
        end;
      end;
    end;
  end;

  // LIC 8
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      d := Dist(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
        CMV[8] := true;
    end;
  end;

  // LIC 9
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      r := MinRadius3(X[i], Y[i], 
                      X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1], 
                      X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2]);
      if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
        CMV[9] := true;
    end;
  end;

  // LIC 10
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      j := i + PARAMETERS.C_PTS + 1;
      k := i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2;
      if ( (REALCOMPARE(X[i], X[j])=EQ) and (REALCOMPARE(Y[i], Y[j])=EQ) ) or
         ( (REALCOMPARE(X[k], X[j])=EQ) and (REALCOMPARE(Y[k], Y[j])=EQ) ) then
        Continue;
      a := CalcAngle(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if (REALCOMPARE(a, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(a, PI + PARAMETERS.EPSILON) = GT) then
        CMV[10] := true;
    end;
  end;

  // LIC 11
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2;
      a := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(a, PARAMETERS.AREA1) = GT then
        CMV[11] := true;
    end;
  end;

  // LIC 12
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    begin
      j := i + PARAMETERS.G_PTS + 1;
      if REALCOMPARE(X[j], X[i]) = LT then
        CMV[12] := true;
    end;
  end;

  // LIC 13
  if NUMPOINTS >= 3 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      d := Dist(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then cond1 := true;
      if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then cond2 := true;
    end;
    CMV[13] := cond1 and cond2;
  end;

  // LIC 14
  if NUMPOINTS >= 5 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      r := MinRadius3(X[i], Y[i], 
                      X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1], 
                      X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2]);
      if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then cond1 := true;
      if REALCOMPARE(r, PARAMETERS.RADIUS2) <> GT then cond2 := true;
    end;
    CMV[14] := cond1 and cond2;
  end;

  // LIC 15
  if NUMPOINTS >= 5 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2;
      a := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(a, PARAMETERS.AREA1) = GT then cond1 := true;
      if REALCOMPARE(a, PARAMETERS.AREA2) = LT then cond2 := true;
    end;
    CMV[15] := cond1 and cond2;
  end;
end;

procedure DECIDE;
var
  i, j: integer;
  row_all_true: boolean;
begin
  CalcLICs;

  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then Continue;
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := true;
        ANDD:    PUM[i, j] := CMV[i] and CMV[j];
        ORR:     PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
  end;

  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      row_all_true := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          row_all_true := false;
          Break;
        end;
      end;
      FUV[i] := row_all_true;
    end;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      Break;
    end;
  end;
end;

{ JSON parser }

type
  TTokenType = (ttString, ttNumber, ttTrue, ttFalse, ttNull, ttLBrace, ttRBrace, ttLBracket, ttRBracket, ttColon, ttComma, ttEOF);

var
  JSONStr: AnsiString;
  JSONPos: Integer;
  CurToken: TTokenType;
  TokenStr: string;
  TokenNum: real;

procedure NextToken;
var
  C: Char;

begin
  while (JSONPos <= Length(JSONStr)) and (JSONStr[JSONPos] in [' ', #9, #10, #13]) do
    Inc(JSONPos);

  if JSONPos > Length(JSONStr) then
  begin
    CurToken := ttEOF;
    Exit;
  end;

  C := JSONStr[JSONPos];
  case C of
    '{': begin CurToken := ttLBrace; Inc(JSONPos); end;
    '}': begin CurToken := ttRBrace; Inc(JSONPos); end;
    '[': begin CurToken := ttLBracket; Inc(JSONPos); end;
    ']': begin CurToken := ttRBracket; Inc(JSONPos); end;
    ':': begin CurToken := ttColon; Inc(JSONPos); end;
    ',': begin CurToken := ttComma; Inc(JSONPos); end;
    '"': 
      begin
        CurToken := ttString;
        Inc(JSONPos);
        TokenStr := '';
        while (JSONPos <= Length(JSONStr)) and (JSONStr[JSONPos] <> '"') do
        begin
          TokenStr := TokenStr + JSONStr[JSONPos];
          Inc(JSONPos);
        end;
        Inc(JSONPos);
      end;
    't', 'T': 
      begin
        CurToken := ttTrue;
        Inc(JSONPos, 4);
      end;
    'f', 'F':
      begin
        CurToken := ttFalse;
        Inc(JSONPos, 5);
      end;
    'n', 'N':
      begin
        CurToken := ttNull;
        Inc(JSONPos, 4);
      end;
    else
      if C in ['-', '0'..'9', '.', 'e', 'E'] then
      begin
        CurToken := ttNumber;
        TokenStr := '';
        while (JSONPos <= Length(JSONStr)) and (JSONStr[JSONPos] in ['-', '0'..'9', '.', 'e', 'E', '+']) do
        begin
          TokenStr := TokenStr + JSONStr[JSONPos];
          Inc(JSONPos);
        end;
        Val(TokenStr, TokenNum);
      end
      else
        Inc(JSONPos);
  end;
end;

procedure Expect(T: TTokenType);
begin
  if CurToken = T then NextToken;
end;

procedure SkipValue; forward;
procedure SkipObject;
begin
  Expect(ttLBrace);
  while CurToken <> ttRBrace do
  begin
    Expect(ttString); Expect(ttColon);
    SkipValue;
    if CurToken = ttComma then NextToken;
  end;
  Expect(ttRBrace);
end;

procedure SkipArray;
begin
  Expect(ttLBracket);
  while CurToken <> ttRBracket do
  begin
    SkipValue;
    if CurToken = ttComma then NextToken;
  end;
  Expect(ttRBracket);
end;

procedure SkipValue;
begin
  case CurToken of
    ttLBrace: SkipObject;
    ttLBracket: SkipArray;
    ttString, ttNumber, ttTrue, ttFalse, ttNull: NextToken;
  end;
end;

procedure ParseInput;
var
  Key: string;
  i, j, NumPointsX, NumPointsY: integer;
begin
  Expect(ttLBrace);
  while CurToken <> ttRBrace do
  begin
    Key := TokenStr;
    Expect(ttString);
    Expect(ttColon);

    if Key = 'numpoints' then
    begin
      NUMPOINTS := Round(TokenNum);
      NextToken;
    end
    else if Key = 'x' then
    begin
      Expect(ttLBracket);
      NumPointsX := 0;
      while CurToken <> ttRBracket do
      begin
        Inc(NumPointsX);
        X[NumPointsX] := TokenNum;
        NextToken;
        if CurToken = ttComma then NextToken;
      end;
      Expect(ttRBracket);
    end
    else if Key = 'y' then
    begin
      Expect(ttLBracket);
      NumPointsY := 0;
      while CurToken <> ttRBracket do
      begin
        Inc(NumPointsY);
        Y[NumPointsY] := TokenNum;
        NextToken;
        if CurToken = ttComma then NextToken;
      end;
      Expect(ttRBracket);
    end
    else if Key = 'parameters' then
    begin
      Expect(ttLBrace);
      while CurToken <> ttRBrace do
      begin
        Key := TokenStr;
        Expect(ttString);
        Expect(ttColon);
        if Key = 'LENGTH1' then PARAMETERS.LENGTH1 := TokenNum
        else if Key = 'RADIUS1' then PARAMETERS.RADIUS1 := TokenNum
        else if Key = 'EPSILON' then PARAMETERS.EPSILON := TokenNum
        else if Key = 'AREA1' then PARAMETERS.AREA1 := TokenNum
        else if Key = 'Q_PTS' then PARAMETERS.Q_PTS := Round(TokenNum)
        else if Key = 'QUADS' then PARAMETERS.QUADS := Round(TokenNum)
        else if Key = 'DIST' then PARAMETERS.DIST := TokenNum
        else if Key = 'N_PTS' then PARAMETERS.N_PTS := Round(TokenNum)
        else if Key = 'K_PTS' then PARAMETERS.K_PTS := Round(TokenNum)
        else if Key = 'A_PTS' then PARAMETERS.A_PTS := Round(TokenNum)
        else if Key = 'B_PTS' then PARAMETERS.B_PTS := Round(TokenNum)
        else if Key = 'C_PTS' then PARAMETERS.C_PTS := Round(TokenNum)
        else if Key = 'D_PTS' then PARAMETERS.D_PTS := Round(TokenNum)
        else if Key = 'E_PTS' then PARAMETERS.E_PTS := Round(TokenNum)
        else if Key = 'F_PTS' then PARAMETERS.F_PTS := Round(TokenNum)
        else if Key = 'G_PTS' then PARAMETERS.G_PTS := Round(TokenNum)
        else if Key = 'LENGTH2' then PARAMETERS.LENGTH2 := TokenNum
        else if Key = 'RADIUS2' then PARAMETERS.RADIUS2 := TokenNum
        else if Key = 'AREA2' then PARAMETERS.AREA2 := TokenNum;

        NextToken;
        if CurToken = ttComma then NextToken;
      end;
      Expect(ttRBrace);
    end
    else if Key = 'lcm' then
    begin
      Expect(ttLBracket);
      for i := 1 to 15 do
      begin
        Expect(ttLBracket);
        for j := 1 to 15 do
        begin
          if TokenStr = 'NOTUSED' then LCM[i,j] := NOTUSED
          else if TokenStr = 'ANDD' then LCM[i,j] := ANDD
          else if TokenStr = 'ORR' then LCM[i,j] := ORR;
          NextToken;
          if CurToken = ttComma then NextToken;
        end;
        Expect(ttRBracket);
        if CurToken = ttComma then NextToken;
      end;
      Expect(ttRBracket);
    end
    else if Key = 'pum_diag' then
    begin
      Expect(ttLBracket);
      for i := 1 to 15 do
      begin
        PUM[i,i] := (CurToken = ttTrue);
        NextToken;
        if CurToken = ttComma then NextToken;
      end;
      Expect(ttRBracket);
    end
    else
      SkipValue;

    if CurToken = ttComma then NextToken;
  end;
  Expect(ttRBrace);
end;

procedure ReadInput;
var
  Line: string;
begin
  JSONStr := '';
  while not Eof do
  begin
    Readln(Line);
    JSONStr := JSONStr + Line + ' ';
  end;
  JSONPos := 1;
  NextToken;
  ParseInput;
end;

procedure WriteOutput;
var
  i, j: integer;
begin
  Write('{"cmv": [');
  for i := 1 to 15 do
  begin
    if CMV[i] then Write('true') else Write('false');
    if i < 15 then Write(', ');
  end;
  Write('], "pum": [');
  for i := 1 to 15 do
  begin
    Write('[');
    for j := 1 to 15 do
    begin
      if PUM[i,j] then Write('true') else Write('false');
      if j < 15 then Write(', ');
    end;
    Write(']');
    if i < 15 then Write(', ');
  end;
  Write('], "fuv": [');
  for i := 1 to 15 do
  begin
    if FUV[i] then Write('true') else Write('false');
    if i < 15 then Write(', ');
  end;
  Write('], "launch": ');
  if LAUNCH then Write('true') else Write('false');
  Writeln('}');
end;

begin
  ReadInput;
  DECIDE;
  WriteOutput;
end.
